var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"그럼 이 앞에 있는 녀석들부터 시작할까?","JPN":"では、前にいる奴らから始めるか。","ENG":"Should we start with these ones in the front?","TWN":"那就從前面這些傢伙開始吧？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"이 정도 침식체들도 감당하지 못 할 수준이면 지상으로 올려보낼 테니 그렇게 알라고.","JPN":"この程度の侵食体もやっつけられないくらいなら地上に戻ってもらう。","ENG":"I'll be sending you back to the surface if you can't even handle C.O.s of this level.","TWN":"如果連這種程度侵蝕體都打不贏，那我會把你們送回樓上。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"어때? 조금은 마녀의 집 같지?","JPN":"どうだ？　少しは魔女の家みたいだろう？","ENG":"What do you think? Feels like a witch's hut, doesn't it?","TWN":"怎麼樣？有點像魔女的家吧？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"카페 지하에…… 침식체들이?","JPN":"カフェの地下に……侵食体が？","ENG":"C.O.s... in the cafe basement?","TWN":"咖啡廳地下室……有侵蝕體？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"오해할까 봐 미리 말해두는 건데, 우리 덕에 이 주변 일대가 안전해진 거다?","JPN":"誤解のないように言っておくが、妾たちのおかげでこの辺りは安全なのだぞ。","ENG":"Just to avoid any misunderstandings, we're the ones who made this neighborhood safer, okay?","TWN":"怕你們誤會，我先說清楚，這附近是托我們的福才能平安度日的。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"이면 세계 좌표를 여기 고정해 둬서……","JPN":"裏世界の座標をここに固定してあるから……","ENG":"We fixed the Counterside coordinates to this location, and...","TWN":"我們把異界座標固定在這裡……"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"아무튼! 악의는 없어. 그것만 알아주면 돼.","JPN":"とにかく！　悪事を働くためではない。それだけわかってくれればいい。","ENG":"Anyway! We don't have any foul intentions. Just know that.","TWN":"總之！我們沒有惡意。你們只需要知道這一點就好。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"호의를 베풀어 주신 분을 의심할 생각은 없습니다.","JPN":"ご好意を示してくださった方を疑うつもりは毛頭ありません。","ENG":"I will not doubt the person who offered us kindness.","TWN":"我們不會懷疑對我們釋出善意的人。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"애초에 반대하시던 걸 저희가 돕겠다 고집을 부린 거니까요.","JPN":"そもそも反対されていたところを、私たちがお手伝いしたいと駄々をこねたわけですから。","ENG":"Besides, we were the ones who insisted on helping, even though you were against it.","TWN":"而且你原本還不讓我們來，是我們堅持要來的。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"게다가 결국 허락해주시지 않았습니까? 저희는 라우라 공의 진의를 의심하지 않습니다.","JPN":"それに、結局はお許しくださったではありませんか。ラウラ殿の意向を信じます。","ENG":"And you eventually gave us permission, too. We have no doubts about your true intentions, Dame Laura.","TWN":"但最後你還是答應我們不是嗎？所以我們不會懷疑蘿拉的。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"믿어주는 건 고마운데, 너무 사람을 쉽게 믿는 거 아냐?","JPN":"信じてくれるのはありがたいが、他人を簡単に信頼しすぎなのではないか？","ENG":"I'm glad you trust me, but don't you think you're too trusting?","TWN":"謝謝你們相信我，但你們會不會太容易相信人啦？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"아무튼, 나랑 플루토가 이쪽을 맡을 테니 너흰 저쪽을 맡아.","JPN":"とにかく、妾とプルートがこちらを引き受けよう。汝らはあちらを頼む。","ENG":"Anyway, Pluto and I will take this side. You two go over there.","TWN":"總之，我和布魯托負責這邊，你們負責那邊。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"위험하면 바로 나를 부르도록 해. 알았지?","JPN":"危険だと思ったらすぐ妾を呼べ。わかったな？","ENG":"Call me if things get dangerous. Okay?","TWN":"如果有危險就馬上叫我。知道嗎？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"냐옹.","JPN":"にゃあ。","ENG":"Meow.","TWN":"喵。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_CAT_START"},{"id":"L23_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"후훗. 네. 알겠습니다.","JPN":"ふふっ。はい、わかりました。","ENG":"Haha. Right. Understood.","TWN":"呵呵。好的，我會的。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"그럼…… 저기부터 시작해볼까?","JPN":"それでは……あちらから始めてみるか。","ENG":"Now then... should we start there?","TWN":"那麼……從那邊開始吧？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"냐옹!","JPN":"にゃあ！","ENG":"Meow!","TWN":"喵！"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_CAT_DAMAGE_DOWN"},{"id":"L29_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"오늘 발톱이 제법 날카로운데? 요즘 몸이 근질근질했나 봐?","JPN":"なんだか今日は爪がやたらと鋭いな。戦いたくてうずうずしていたのか？","ENG":"Your claws are looking sharper than usual. Been itching to fight?","TWN":"今天的爪子還真是利呢？最近身體很癢嗎？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"냐옹!","JPN":"にゃあ！","ENG":"Meow!","TWN":"喵！"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_CAT_START"},{"id":"L31_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"하지만 이 앞까지 2종이 이렇게 많을 줄이야.","JPN":"だが、まだ手前なのに第2種がこれほど多いとは。","ENG":"But I didn't think there'd be this many Category 2s out here.","TWN":"不過沒想到前面有這麼多2類侵蝕體。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"에블린 말대로, 위험한 녀석이 튀어나올지도 모르겠어.","JPN":"エヴリンの言うとおり、危ない奴が出てくるかもしれない。","ENG":"I might encounter some of the more menacing ones, like Evelyn said.","TWN":"或許就像伊芙琳說的，可能會有危險的傢伙出現。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"손님들? 좀 위험하지 않아? 내가 바로 갈……","JPN":"お客さんたち？　少々危険ではないか？　すぐ妾がそちらに……","ENG":"Hey, you two. You look like you're in danger, I'll be right there–","TWN":"二位客人？這有點危險，不如我來……"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"그냥 이렇게 베기만 하는 거라면, 제 재주도 도움이 되겠군요.","JPN":"ただこうやって斬るだけでしたら、私でも役に立てそうですね。","ENG":"If swinging my sword is all it takes, perhaps I could be of use here.","TWN":"如果只需要這樣砍，那我的技能應該能能派上用場。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"와~ 치후유. 잘했어. 어디 다친 데는 없니?","JPN":"わあ～千冬。上手だわ。怪我はしてない？","ENG":"Wow, Chifuyu! Great job. Are you hurt?","TWN":"哇～千冬，做得好。有沒有受傷？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"당주님께서 함께해주신 덕에 다친 곳은 없습니다.","JPN":"当主が付いてきてくださったおかげで、怪我はありません。","ENG":"Not at all, thanks to you, my lady.","TWN":"多虧堂主的幫助，我沒有受傷。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"걱정한 내가 바보였군.","JPN":"心配して損したな。","ENG":"I guess I was the fool for worrying.","TWN":"我真蠢，瞎擔心什麼。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"야옹……","JPN":"にゃあ……","ENG":"Meow...","TWN":"喵……"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_CAT_DAMAGE_DOWN"},{"id":"L44_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"동생이야 호위 무사랬으니 어느 정도 실력은 있어 보였는데, 꼬맹이도 잘 싸우잖아?","JPN":"妹は護衛と言っていたからある程度実力はあるだろうとは思ったが、ちびっ子もなかなかやるではないか。","ENG":"Since the younger one is the bodyguard, I thought she might be strong enough, but I didn't think the kid could fight too.","TWN":"妹妹是護衛武士，看起來功夫是不錯，沒想到另一個小鬼也蠻會打的？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"당주라는 이름이 폼은 아니었나 보네.","JPN":"当主の名は伊達ではなかったようだ。","ENG":"I guess being the head of a family is more than just a title.","TWN":"看來堂主這個名號不是浪得虛名。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"다치지 말고 잘 싸워보라고. 나도 같이 싸울 테니까.","JPN":"怪我なく、うまく戦ってみろ。妾も一緒に戦おう。","ENG":"Be careful not to get hurt while you fight. I'll fight with you two.","TWN":"好好打，不要受傷。我也會一起打的。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CHIFUYU_NANA_CA_NULL","text":{"KOREA":"알겠습니다. 라우라 공, 그럼 소탕을 시작하겠습니다.","JPN":"わかりました、ラウラ殿。それでは掃討を始めます。","ENG":"Understood. Let us start the extermination, Dame Laura.","TWN":"好的，蘿拉，那現在開始掃蕩。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"언니도 뒤에서 가세할게.","JPN":"私も後ろで加勢するわ。","ENG":"I will offer assistance from behind.","TWN":"姊姊也會在後面幫忙的。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_CA_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};